// Save last values in context
let last = context.get('lastValues') || {};

// Extract current values
let t = msg.payload["esp32/temp"];
let h = msg.payload["esp32/hum"];
let s = msg.payload["esp32/soil"];

// Define change tolerance (optional)
let delta = 2;

// Compare
if (
    last.temp !== undefined &&
    Math.abs(t - last.temp) < delta &&
    Math.abs(h - last.hum) < delta &&
    Math.abs(s - last.soil) < 100
) {
    // No significant change → skip
    return null;
}

// Update stored values
context.set('lastValues', { temp: t, hum: h, soil: s });

// Forward message
msg.payload = { temp: t, hum: h, soil: s };
return msg;

if (msg.payload === "ON") {
    msg.topic = "INSERT INTO irrigation_sessions (start_time) VALUES (datetime('now'))";
} else if (msg.payload === "OFF") {
    msg.topic = "UPDATE irrigation_sessions SET stop_time = datetime('now') WHERE stop_time IS NULL";
}
return msg;

let t = msg.payload.temp;
let h = msg.payload.hum;
let s = msg.payload.soil;

msg.topic = `INSERT INTO sensor_data (temp, hum, soil) VALUES (${t}, ${h}, ${s})`;
return msg;

let limit = msg.sensorLimit || 20;
msg.topic = `SELECT * FROM sensor_data ORDER BY timestamp DESC LIMIT ${limit}`;
return msg;

let n = parseInt(msg.irrigationLimit)||20;
msg.topic = `
  SELECT id,start_time,stop_time 
    FROM irrigation_sessions 
   WHERE stop_time IS NOT NULL 
ORDER BY start_time DESC 
   LIMIT ${n}
`;
return msg;

if (msg.payload && msg.payload.length && msg.payload[0].temp !== undefined) return [msg, null];
if (msg.payload && msg.payload.length && msg.payload[0].start_time !== undefined) return [null, msg];
return null;

let temp = msg.payload.reverse().map(row => ({ x: Date.parse(row.timestamp), y: row.temp }));
msg.payload = [{ series: ["Temp"], data: [temp], labels: [] }];
return msg;

let hum = msg.payload.reverse().map(row => ({ x: Date.parse(row.timestamp), y: row.hum }));
msg.payload = [{ series: ["Humidity"], data: [hum], labels: [] }];
return msg;

let soil = msg.payload.reverse().map(row => ({ x: Date.parse(row.timestamp), y: row.soil }));
msg.payload = [{ series: ["Soil"], data: [soil], labels: [] }];
return msg;

// 0. Time throttle
let now = Date.now();
let lastRun = flow.get("lastIrrigationRun") || 0;
let interval = 20 * 1 * 1000;

if (now - lastRun < interval) {
    //return { payload: "OFF" };
    return null;
}
flow.set("lastIrrigationRun", now);

// 1. Mode check
let mode = flow.get("mode") || "auto";
if (mode !== "auto") return null;

// 2. Rain check
//let rain = flow.get("willRain") || false;
//if (rain) {
  //  node.warn("Skipping irrigation: rain expected");
    //return { payload: "OFF" };
//}

// 3. Sensor unpack
let { temp, hum, soil } = msg.payload || {};
if (temp === undefined || hum === undefined || soil === undefined) {
    node.warn("Missing sensor data");
    return null;
}

// ✅ 3.1 Force numeric conversion (fixes false positives)
temp = Number(temp);
hum  = Number(hum);
soil = Number(soil);

// 4. Hot hours check
let hour = new Date().getHours();
if (hour >= 9 && hour <= 14) {
    node.warn("Skipped due to heat hours");
    return { payload: "OFF" };
}

// 5. Get thresholds
let soilMin = flow.get('soilMin') ?? 3000;
let soilMax = flow.get('soilMax') ?? 3950;
let tempMax = flow.get('tempMax') ?? 30;
let humMin  = flow.get('humMin')  ?? 35;

// 6. Final logic
if (
    !isNaN(soil) && !isNaN(temp) && !isNaN(hum) &&
    soil > soilMin && soil < soilMax &&
    temp < tempMax &&
    hum > humMin
) {
    node.warn("Pump ON: conditions met");
    node.warn(`Sensor check → soil=${soil}, temp=${temp}, hum=${hum}`);
    return { payload: "ON" };
} else {
    node.warn(`Pump OFF: conditions not met → soil=${soil}, temp=${temp}, hum=${hum}`);
    return { payload: "OFF" };
}

msg.payload = {
  soil: msg.payload["esp32/soil"],
  temp: msg.payload["esp32/temp"],
  hum: msg.payload["esp32/hum"]
};
return msg;

let forecast = msg.payload.list || [];

let willRain = forecast.some(entry => {
    return entry.rain && entry.rain["3h"] > 0;
});

flow.set("willRain", willRain);
node.warn("Rain expected? " + willRain);

return msg;  // so you can pass it to the template too

// msg.payload is array of rows [{start_time,stop_time},…]
let rows = msg.payload || [];

let bars = [];
let labels = [];

for (let r of rows) {
  if (!r.start_time || !r.stop_time) continue;
  let start = new Date(r.start_time).getTime();
  let stop  = new Date(r.stop_time).getTime();
  let dur   = +(((stop - start) / 60000).toFixed(1));
  let label = new Date(start).toLocaleString();
  bars.push(dur);
  labels.push(label);
}

// Build a single msg.payload that replaces the chart data
msg.payload = [
  {
    series: ["Duration (min)"],
    data: [bars],
    labels: labels
  }
];
return msg;

// read all four values from flow
